type AlphaHeartbeat struct {
    RestingInterval float64   // seconds (default 120)
    Tau             float64   // decay constant (default 300)
    Heat            float64   // current activity heat
    LastUpdate      time.Time // when heat was last computed
    FloorInterval   float64   // minimum interval (10s)
    CeilInterval    float64   // maximum interval (300s)
}

func (a *AlphaHeartbeat) AddHeat(amount float64) {
    a.decayHeat()
    a.Heat += amount
}

func (a *AlphaHeartbeat) decayHeat() {
    elapsed := time.Since(a.LastUpdate).Seconds()
    a.Heat *= math.Exp(-elapsed / a.Tau)
    a.LastUpdate = time.Now()
}

func (a *AlphaHeartbeat) Interval() time.Duration {
    a.decayHeat()
    // Invert: high heat -> short interval (fast heartbeat)
    raw := a.RestingInterval * math.Exp(-a.Heat)
    clamped := math.Max(a.FloorInterval, math.Min(a.CeilInterval, raw))
    return time.Duration(clamped * float64(time.Second))
}
